  { id: 2, question: '给定属性集 U={A,B,C,D,E} 与函数依赖，求候选码。', knowledge: '候选码', difficulty: '困难', wrong: 'A,C', right: 'A,D', count: 3, date: '昨天 20:18', mastery: 52, mastered: false },
